import { MakeLogicType, afterMount, connect, kea, path } from 'kea'

import { teamLogic } from 'scenes/teamLogic'


const POLL_INTERVAL_MS = 30_000

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface noEventsBannerLogicActions {
    loadCurrentTeam: () => any; // teamLogic
}

export type noEventsBannerLogicType = MakeLogicType<{}, noEventsBannerLogicActions>;

export const noEventsBannerLogic = kea<noEventsBannerLogicType>([
    path(['layout', 'navigation', 'noEventsBannerLogic']),
    connect(() => ({
        actions: [teamLogic, ['loadCurrentTeam']],
    })),
    afterMount(({ actions, cache }) => {
        cache.disposables.add(() => {
            const pollTimer = window.setInterval(() => {
                actions.loadCurrentTeam()
            }, POLL_INTERVAL_MS)
            return () => clearInterval(pollTimer)
        })
    }),
])
